import { afterEach, describe, expect, it } from 'vitest';
import { resolveGoPackagePath } from '../../../../../src/extension/pipeline/plugins/treesitter/runtime/projectRoots/goPackagePath';
import {
  cleanupProjectRootsWorkspaces,
  createProjectRootsWorkspace,
  writeProjectRootsFile,
} from './workspace';

afterEach(() => {
  cleanupProjectRootsWorkspaces();
});

describe('pipeline/plugins/treesitter/runtime/projectRoots/goPackagePath', () => {
  it('prefers a direct package file when the import resolves to package.go', () => {
    const workspaceRoot = createProjectRootsWorkspace();
    const filePath = writeProjectRootsFile(workspaceRoot, 'cmd/app/main.go');
    const directFilePath = writeProjectRootsFile(workspaceRoot, 'internal.go', 'package internal\n');
    writeProjectRootsFile(workspaceRoot, 'go.mod', 'module github.com/acme/project\n');

    expect(
      resolveGoPackagePath(filePath, workspaceRoot, 'github.com/acme/project/internal'),
    ).toBe(directFilePath);
  });

  it('falls back to the first non-test file in the package directory', () => {
    const workspaceRoot = createProjectRootsWorkspace();
    const filePath = writeProjectRootsFile(workspaceRoot, 'cmd/app/main.go');
    const alphaPath = writeProjectRootsFile(workspaceRoot, 'pkg/api/alpha.go', 'package api\n');
    writeProjectRootsFile(workspaceRoot, 'pkg/api/alpha_test.go', 'package api\n');
    writeProjectRootsFile(workspaceRoot, 'pkg/api/zeta.go', 'package api\n');
    writeProjectRootsFile(workspaceRoot, 'go.mod', 'module github.com/acme/project\n');

    expect(
      resolveGoPackagePath(filePath, workspaceRoot, 'github.com/acme/project/pkg/api'),
    ).toBe(alphaPath);
  });

  it('resolves the root package directory when the import path matches the module name', () => {
    const workspaceRoot = createProjectRootsWorkspace();
    const filePath = writeProjectRootsFile(workspaceRoot, 'cmd/app/main.go');
    const rootPackagePath = writeProjectRootsFile(workspaceRoot, 'app.go', 'package project\n');
    writeProjectRootsFile(workspaceRoot, 'go.mod', 'module github.com/acme/project\n');

    expect(
      resolveGoPackagePath(filePath, workspaceRoot, 'github.com/acme/project'),
    ).toBe(rootPackagePath);
  });

  it('returns null when the package directory is missing, not a directory, or only contains test files', () => {
    const workspaceRoot = createProjectRootsWorkspace();
    const filePath = writeProjectRootsFile(workspaceRoot, 'cmd/app/main.go');
    writeProjectRootsFile(workspaceRoot, 'pkg/onlytests/api_test.go', 'package api\n');
    writeProjectRootsFile(workspaceRoot, 'pkg/not-a-dir', 'plain file');
    writeProjectRootsFile(workspaceRoot, 'go.mod', 'module github.com/acme/project\n');

    expect(
      resolveGoPackagePath(filePath, workspaceRoot, 'github.com/acme/project/pkg/missing'),
    ).toBeNull();
    expect(
      resolveGoPackagePath(filePath, workspaceRoot, 'github.com/acme/project/pkg/not-a-dir'),
    ).toBeNull();
    expect(
      resolveGoPackagePath(filePath, workspaceRoot, 'github.com/acme/project/pkg/onlytests'),
    ).toBeNull();
  });

  it('returns null when no go.mod can be found between the file and workspace root', () => {
    const workspaceRoot = createProjectRootsWorkspace();
    const filePath = writeProjectRootsFile(workspaceRoot, 'cmd/app/main.go');
    writeProjectRootsFile(workspaceRoot, 'pkg/api/alpha.go', 'package api\n');

    expect(
      resolveGoPackagePath(filePath, workspaceRoot, 'github.com/acme/project/pkg/api'),
    ).toBeNull();
  });

  it('returns null when the package cannot be resolved inside the module', () => {
    const workspaceRoot = createProjectRootsWorkspace();
    const filePath = writeProjectRootsFile(workspaceRoot, 'cmd/app/main.go');
    writeProjectRootsFile(workspaceRoot, 'go.mod', 'module github.com/acme/project\n');

    expect(
      resolveGoPackagePath(filePath, workspaceRoot, 'github.com/other/project/pkg/api'),
    ).toBeNull();
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import {
  getImportedBindingByIdentifier,
  getImportedBindingByPropertyAccess,
} from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/bindingLookup';
import { getIdentifierText } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/text';

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/text', () => ({
  getIdentifierText: vi.fn(),
}));

function createNode(overrides: Partial<{
  type: string;
  namedChildren: unknown[];
  childForFieldName: (name: string) => unknown;
}> = {}) {
  return {
    type: 'identifier',
    namedChildren: [],
    childForFieldName: () => null,
    ...overrides,
  };
}

describe('pipeline/plugins/treesitter/runtime/analyze/bindingLookup', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('resolves identifier bindings from the imported binding map', () => {
    const binding = { importedName: 'run', specifier: './run', resolvedPath: '/workspace/run.ts' };
    vi.mocked(getIdentifierText).mockReturnValue('run');

    expect(getImportedBindingByIdentifier(createNode() as never, new Map([['run', binding]]))).toBe(binding);
  });

  it('returns null when the identifier text is missing or unknown', () => {
    vi.mocked(getIdentifierText).mockReturnValueOnce(null).mockReturnValueOnce('missing');

    expect(getImportedBindingByIdentifier(createNode() as never, new Map())).toBeNull();
    expect(getImportedBindingByIdentifier(createNode() as never, new Map())).toBeNull();
  });

  it('reads property access objects from the requested field before falling back to the first named child', () => {
    const fieldNode = createNode({ type: 'identifier' });
    const fallbackNode = createNode({ type: 'identifier' });
    const fieldBinding = { importedName: 'services', specifier: './services', resolvedPath: null };
    const fallbackBinding = { importedName: 'pkg', specifier: './pkg', resolvedPath: null };
    vi.mocked(getIdentifierText).mockImplementation((node) => {
      if (node === fieldNode) {
        return 'services';
      }

      if (node === fallbackNode) {
        return 'pkg';
      }

      return null;
    });

    expect(
      getImportedBindingByPropertyAccess(
        createNode({
          type: 'selector_expression',
          namedChildren: [fallbackNode],
          childForFieldName: (name: string) => {
            expect(name).toBe('operand');
            return fieldNode;
          },
        }) as never,
        new Map([
          ['services', fieldBinding],
          ['pkg', fallbackBinding],
        ]),
        'selector_expression',
        'operand',
      ),
    ).toBe(fieldBinding);

    expect(
      getImportedBindingByPropertyAccess(
        createNode({
          type: 'selector_expression',
          namedChildren: [fallbackNode],
        }) as never,
        new Map([['pkg', fallbackBinding]]),
        'selector_expression',
        'operand',
      ),
    ).toBe(fallbackBinding);
  });

  it('returns null for mismatched access nodes', () => {
    expect(
      getImportedBindingByPropertyAccess(
        null,
        new Map(),
        'selector_expression',
        'operand',
      ),
    ).toBeNull();
    expect(
      getImportedBindingByPropertyAccess(
        createNode({ type: 'call_expression' }) as never,
        new Map(),
        'selector_expression',
        'operand',
      ),
    ).toBeNull();
    expect(getIdentifierText).not.toHaveBeenCalled();
  });
});

import * as path from 'node:path';
import { afterEach, describe, expect, it } from 'vitest';
import {
  dedupePaths,
  findNearestProjectRoot,
} from '../../../../../src/extension/pipeline/plugins/treesitter/runtime/projectRoots/shared';
import {
  cleanupProjectRootsWorkspaces,
  createProjectRootsWorkspace,
  writeProjectRootsFile,
} from './workspace';

afterEach(() => {
  cleanupProjectRootsWorkspaces();
});

describe('pipeline/plugins/treesitter/runtime/projectRoots/shared', () => {
  it('finds the nearest marker while staying inside the workspace root', () => {
    const workspaceRoot = createProjectRootsWorkspace();
    const projectRoot = path.join(workspaceRoot, 'packages', 'api');
    const filePath = writeProjectRootsFile(workspaceRoot, 'packages/api/src/index.py');
    writeProjectRootsFile(workspaceRoot, 'packages/api/pyproject.toml');

    expect(findNearestProjectRoot(filePath, ['pyproject.toml'], workspaceRoot)).toBe(projectRoot);
  });

  it('returns the workspace root when the nearest marker lives at the workspace boundary', () => {
    const workspaceRoot = createProjectRootsWorkspace();
    const filePath = writeProjectRootsFile(workspaceRoot, 'src/index.py');
    writeProjectRootsFile(workspaceRoot, 'pyproject.toml');

    expect(findNearestProjectRoot(filePath, ['pyproject.toml'], workspaceRoot)).toBe(workspaceRoot);
  });

  it('returns null when no marker exists before leaving the workspace root', () => {
    const workspaceRoot = createProjectRootsWorkspace();
    const filePath = writeProjectRootsFile(workspaceRoot, 'packages/api/src/index.py');

    expect(findNearestProjectRoot(filePath, ['pyproject.toml'], workspaceRoot)).toBeNull();
  });

  it('does not walk outside the workspace root when a parent directory has a matching marker', () => {
    const workspaceRoot = createProjectRootsWorkspace();
    const outerRoot = path.dirname(workspaceRoot);
    const filePath = writeProjectRootsFile(workspaceRoot, 'packages/api/src/index.py');
    writeProjectRootsFile(outerRoot, 'pyproject.toml');

    expect(findNearestProjectRoot(filePath, ['pyproject.toml'], workspaceRoot)).toBeNull();
  });

  it('returns null when the requested file path already starts outside the workspace root', () => {
    const workspaceRoot = createProjectRootsWorkspace();
    const outsideRoot = createProjectRootsWorkspace();
    const outsideFilePath = writeProjectRootsFile(outsideRoot, 'src/index.py');
    writeProjectRootsFile(outsideRoot, 'pyproject.toml');

    expect(findNearestProjectRoot(outsideFilePath, ['pyproject.toml'], workspaceRoot)).toBeNull();
  });

  it('deduplicates and removes empty paths', () => {
    const workspaceRoot = createProjectRootsWorkspace();

    expect(
      dedupePaths([workspaceRoot, '', null, `${workspaceRoot}/src`, workspaceRoot, undefined]),
    ).toEqual([workspaceRoot, `${workspaceRoot}/src`]);
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import { addNamedImportBindings } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/importClauseNamedBindings';
import { addCollectedImportBinding } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/importClauseCollectedBinding';

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/importClauseCollectedBinding', () => ({
  addCollectedImportBinding: vi.fn(),
}));

function createNode(overrides: Partial<{
  type: string;
  text: string;
  namedChildren: unknown[];
}> = {}) {
  return {
    type: 'identifier',
    text: '',
    namedChildren: [],
    ...overrides,
  };
}

describe('pipeline/plugins/treesitter/runtime/analyze/importClauseNamedBindings', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('collects import specifiers from identifiers and type identifiers', () => {
    const importedBindings = new Map();

    addNamedImportBindings(
      createNode({
        type: 'named_imports',
        namedChildren: [
          createNode({
            type: 'import_specifier',
            namedChildren: [
              createNode({ type: 'identifier', text: 'original' }),
              createNode({ type: 'identifier', text: 'alias' }),
            ],
          }),
          createNode({
            type: 'import_specifier',
            namedChildren: [createNode({ type: 'type_identifier', text: 'Service' })],
          }),
          createNode({ type: 'comment' }),
        ],
      }) as never,
      importedBindings,
      './lib',
      '/workspace/lib.ts',
    );

    expect(addCollectedImportBinding).toHaveBeenNthCalledWith(
      1,
      importedBindings,
      'alias',
      'original',
      './lib',
      '/workspace/lib.ts',
    );
    expect(addCollectedImportBinding).toHaveBeenNthCalledWith(
      2,
      importedBindings,
      'Service',
      'Service',
      './lib',
      '/workspace/lib.ts',
    );
  });

  it('skips specifiers without a local identifier', () => {
    addNamedImportBindings(
      createNode({
        type: 'named_imports',
        namedChildren: [
          createNode({
            type: 'import_specifier',
            namedChildren: [createNode({ type: 'string', text: '"ignored"' })],
          }),
        ],
      }) as never,
      new Map(),
      './lib',
      null,
    );

    expect(addCollectedImportBinding).not.toHaveBeenCalled();
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import { loadWorkspaceAnalysisDatabaseCache } from '../../../../src/extension/pipeline/database/cacheLoad';
