import { clearDatabaseArtifacts, getWorkspaceAnalysisDatabasePath } from '../../../../src/extension/pipeline/database/cachePaths';
import { createSnapshotFileEntry } from '../../../../src/extension/pipeline/database/cacheRows';

vi.mock('node:fs', () => ({
  default: {
    existsSync: vi.fn(),
  },
  existsSync: vi.fn(),
}));

vi.mock('../../../../src/extension/pipeline/cache', () => ({
  createEmptyWorkspaceAnalysisCache: vi.fn(),
  WORKSPACE_ANALYSIS_CACHE_VERSION: '2.0.0',
}));

vi.mock('../../../../src/extension/pipeline/database/cacheConnection', () => ({
  readRowsSync: vi.fn(),
  withConnection: vi.fn(),
}));

vi.mock('../../../../src/extension/pipeline/database/cachePaths', () => ({
  clearDatabaseArtifacts: vi.fn(),
  getWorkspaceAnalysisDatabasePath: vi.fn(),
}));

vi.mock('../../../../src/extension/pipeline/database/cacheRows', () => ({
  createSnapshotFileEntry: vi.fn(),
}));

const fsModule = await import('node:fs');

describe('extension/pipeline/database/cacheLoad', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    vi.mocked(getWorkspaceAnalysisDatabasePath).mockReturnValue('/workspace/.codegraphy/graph.lbug');
    vi.mocked(createEmptyWorkspaceAnalysisCache).mockImplementation(() => ({
      version: '0.0.0',
      files: {},
    }) as never);
  });

  it('returns an empty cache when the database file does not exist', () => {
    vi.mocked(fsModule.existsSync).mockReturnValue(false);

    expect(loadWorkspaceAnalysisDatabaseCache('/workspace')).toEqual({
      version: '0.0.0',
      files: {},
    });
    expect(withConnection).not.toHaveBeenCalled();
  });

  it('loads readable rows, skips empty entries, and warns for unreadable rows', () => {
    const warn = vi.spyOn(console, 'warn').mockImplementation(() => undefined);
    vi.mocked(fsModule.existsSync).mockReturnValue(true);
    vi.mocked(withConnection).mockImplementation((_databasePath, callback) => callback('connection' as never));
    vi.mocked(readRowsSync).mockReturnValue(['good-row', 'empty-row', 'bad-row'] as never);
    vi.mocked(createSnapshotFileEntry)
      .mockReturnValueOnce({
        filePath: 'src/app.ts',
        mtime: 1,
        size: 2,
        analysis: { filePath: '/workspace/src/app.ts', relations: [] },
      } as never)
      .mockImplementationOnce(() => null as never)
      .mockImplementationOnce(() => {
        throw new Error('bad row');
      });

    expect(loadWorkspaceAnalysisDatabaseCache('/workspace')).toEqual({
      version: WORKSPACE_ANALYSIS_CACHE_VERSION,
      files: {
        'src/app.ts': {
          mtime: 1,
          size: 2,
          analysis: { filePath: '/workspace/src/app.ts', relations: [] },
        },
      },
    });
    expect(createSnapshotFileEntry).toHaveBeenCalledTimes(3);
    expect(readRowsSync).toHaveBeenCalledWith('connection', expect.any(String));
    expect(warn).toHaveBeenCalledTimes(1);
    expect(warn).toHaveBeenCalledWith('[CodeGraphy] Skipping unreadable persisted analysis row.', expect.any(Error));
  });

  it('clears broken database artifacts and falls back to an empty cache when the database read fails', () => {
    const warn = vi.spyOn(console, 'warn').mockImplementation(() => undefined);
    vi.mocked(fsModule.existsSync).mockReturnValue(true);
    vi.mocked(withConnection).mockImplementation(() => {
      throw new Error('sqlite error');
    });

    expect(loadWorkspaceAnalysisDatabaseCache('/workspace')).toEqual({
      version: '0.0.0',
      files: {},
    });
    expect(clearDatabaseArtifacts).toHaveBeenCalledWith('/workspace/.codegraphy/graph.lbug');
    expect(warn).toHaveBeenCalledWith(
      '[CodeGraphy] Failed to read persisted analysis database. Rebuilding cache.',
      expect.any(Error),
    );
  });
});

import { describe, expect, it, vi } from 'vitest';
import { walkSymbolBody, walkTree } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/walk';

function createNode(overrides: Partial<{
  type: string;
  namedChildren: unknown[];
  childForFieldName: (name: string) => unknown;
}> = {}) {
  return {
    type: 'node',
    namedChildren: [],
    childForFieldName: () => null,
    ...overrides,
  };
}

describe('pipeline/plugins/treesitter/runtime/analyze/walk', () => {
  it('recursively walks child nodes with the current or updated context', () => {
    const child = createNode({ type: 'child' });
    const grandchild = createNode({ type: 'grandchild' });
    const root = createNode({ type: 'root', namedChildren: [createNode({ type: 'middle', namedChildren: [grandchild] }), child] });
    const visits: string[] = [];

    walkTree(root as never, 'root-context', (node, context) => {
      visits.push(`${node.type}:${context}`);
      if (node.type === 'root') {
        return { nextContext: 'nested-context' };
      }

      return undefined;
    });

    expect(visits).toEqual([
      'root:root-context',
      'middle:nested-context',
      'grandchild:nested-context',
      'child:nested-context',
    ]);
  });

  it('skips children when the visitor requests it', () => {
    const visits: string[] = [];

    walkTree(
      createNode({ type: 'root', namedChildren: [createNode({ type: 'child' })] }) as never,
      null,
      (node) => {
        visits.push(node.type);
        return { skipChildren: true };
      },
    );

    expect(visits).toEqual(['root']);
  });

  it('walks symbol bodies through the body field or final named child', () => {
    const walk = vi.fn();
    const fieldBody = createNode({ type: 'block' });
    const fallbackBody = createNode({ type: 'fallback-block' });

    expect(
      walkSymbolBody(
        createNode({ childForFieldName: (name: string) => (name === 'body' ? fieldBody : null) }) as never,
        'symbol-id',
        walk,
      ),
    ).toEqual({ skipChildren: true });
    expect(
      walkSymbolBody(
        createNode({ namedChildren: [fallbackBody], childForFieldName: () => null }) as never,
        'symbol-id',
        walk,
      ),
    ).toEqual({ skipChildren: true });
    expect(
      walkSymbolBody(createNode() as never, 'symbol-id', walk),
    ).toEqual({ skipChildren: true });

    expect(walk).toHaveBeenCalledTimes(2);
    expect(walk).toHaveBeenNthCalledWith(1, fieldBody, { currentSymbolId: 'symbol-id' });
    expect(walk).toHaveBeenNthCalledWith(2, fallbackBody, { currentSymbolId: 'symbol-id' });
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import { TREE_SITTER_SOURCE_IDS } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/languages';
import { getImportRelationForJavaScriptCallExpression } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/javascriptCallImports';

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/resolve', () => ({
  resolveTreeSitterImportPath: vi.fn(() => '/workspace/src/utils.ts'),
}));

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/nodes', () => ({
  getIdentifierText: vi.fn(),
  getStringSpecifier: vi.fn(),
}));

import { resolveTreeSitterImportPath } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/resolve';
import { getIdentifierText, getStringSpecifier } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/nodes';

function createCallExpression(overrides: {
  calleeNode?: unknown;
  argumentsNode?: { namedChildren: Array<{ type: string; text?: string; name?: string }> };
  namedChildren?: unknown[];
} = {}) {
  const calleeNode = overrides.calleeNode ?? { type: 'identifier' };
  const argumentsNode = overrides.argumentsNode ?? {
    namedChildren: [{ type: 'string' }],
  };

  return {
    childForFieldName: (field: string) => {
      if (field === 'function') {
        return calleeNode;
      }
      if (field === 'arguments') {
        return argumentsNode;
      }
      return null;
    },
    namedChildren: overrides.namedChildren ?? [calleeNode, argumentsNode],
  };
}

describe('pipeline/treesitter/javascriptCallImports', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    vi.mocked(getStringSpecifier).mockImplementation((node) => (node as { text?: string } | null)?.text ?? null);
    vi.mocked(getIdentifierText).mockImplementation((node) => (node as { name?: string } | null)?.name ?? null);
    vi.mocked(resolveTreeSitterImportPath).mockImplementation((_filePath, specifier) => {
      if (specifier === './missing') {
        return null;
      }
      return `/workspace/src/${specifier.replace('./', '')}.ts`;
    });
  });

  it('returns null when the call does not contain any arguments node or string specifier', () => {
    const callExpression = {
      childForFieldName: () => null,
      namedChildren: [{ type: 'identifier', name: 'require' }],
    };

    expect(
      getImportRelationForJavaScriptCallExpression(
        callExpression as never,
        '/workspace/src/index.ts',
      ),
    ).toBeNull();
    expect(resolveTreeSitterImportPath).not.toHaveBeenCalled();
  });

  it('builds a dynamic import relation from named-children fallbacks and interpreted string nodes', () => {
    const callExpression = {
      childForFieldName: (field: string) => {
        if (field === 'function' || field === 'arguments') {
          return null;
        }
        return null;
      },
      namedChildren: [
        { type: 'import' },
        {
          type: 'arguments',
          namedChildren: [
            { type: 'identifier', text: 'ignored' },
            { type: 'interpreted_string_literal', text: './utils' },
          ],
        },
      ],
    };

    expect(
      getImportRelationForJavaScriptCallExpression(
        callExpression as never,
        '/workspace/src/index.ts',
      ),
    ).toEqual({
      kind: 'import',
      sourceId: TREE_SITTER_SOURCE_IDS.dynamicImport,
      fromFilePath: '/workspace/src/index.ts',
      specifier: './utils',
      resolvedPath: '/workspace/src/utils.ts',
      toFilePath: '/workspace/src/utils.ts',
      type: 'dynamic',
    });
    expect(resolveTreeSitterImportPath).toHaveBeenCalledWith('/workspace/src/index.ts', './utils');
  });

  it('returns null when the callee is not require', () => {
    expect(
      getImportRelationForJavaScriptCallExpression(
        createCallExpression({
          calleeNode: { type: 'identifier', name: 'loadModule' },
          argumentsNode: {
            namedChildren: [{ type: 'string', text: './utils' }],
          },
        }) as never,
        '/workspace/src/index.ts',
      ),
    ).toBeNull();
  });

  it('builds a commonjs import relation for require calls even when the path does not resolve', () => {
    expect(
