function createNode({
  type = 'identifier',
  fields = {},
  namedChildren = [],
}: {
  type?: string;
  fields?: Record<string, Parser.SyntaxNode | null | undefined>;
  namedChildren?: Parser.SyntaxNode[];
} = {}): Parser.SyntaxNode {
  return {
    type,
