        },
      }) as never,
      '/workspace/App.java',
      null,
      null,
      [] as never[],
      symbols as never,
      new Map(),
    );
    handleJavaTypeDeclaration(
      createNode({
        type: 'enum_declaration',
        childForFieldName: (name: string) => {
          expect(['name', 'superclass']).toContain(name);
          return name === 'name' ? createNode({ type: 'identifier' }) : null;
        },
      }) as never,
      '/workspace/App.java',
      null,
      null,
      [] as never[],
      symbols as never,
      new Map(),
    );
    handleJavaTypeDeclaration(
      createNode({
        type: 'class_declaration',
        childForFieldName: (name: string) => {
          expect(['name', 'superclass']).toContain(name);
          return null;
        },
      }) as never,
      '/workspace/App.java',
      null,
      null,
      [] as never[],
      symbols as never,
      new Map(),
