import { beforeEach, describe, expect, it, vi } from 'vitest';
import {
  hasWorkspacePipelineIndex,
  persistWorkspacePipelineIndexMetadata,
} from '../../../../src/extension/pipeline/service/index';
import {
  readCodeGraphyRepoMeta,
  writeCodeGraphyRepoMeta,
} from '../../../../src/extension/repoSettings/meta';
import type { ICodeGraphyRepoMeta } from '../../../../src/extension/repoSettings/meta';

vi.mock('../../../../src/extension/repoSettings/meta', () => ({
  readCodeGraphyRepoMeta: vi.fn(),
  writeCodeGraphyRepoMeta: vi.fn(),
}));

describe('pipeline/service/index', () => {
  const meta = (overrides: Partial<ICodeGraphyRepoMeta> = {}): ICodeGraphyRepoMeta => ({
    version: 1,
    lastIndexedAt: '2026-01-01T00:00:00.000Z',
    lastIndexedCommit: 'abc123',
    pluginSignature: 'plugin-signature',
    settingsSignature: 'settings-signature',
    pendingChangedFiles: [],
    ...overrides,
  });

  beforeEach(() => {
    vi.clearAllMocks();
    vi.useRealTimers();
    vi.mocked(readCodeGraphyRepoMeta).mockReturnValue(meta());
  });

  it('returns false when no workspace root or no persisted index timestamp exists', () => {
    const dependencies = {
      getCurrentCommitShaSync: vi.fn(),
      getPluginSignature: vi.fn(() => 'plugin-signature'),
      getSettingsSignature: vi.fn(() => 'settings-signature'),
    };

    expect(hasWorkspacePipelineIndex(undefined, dependencies)).toBe(false);
    expect(readCodeGraphyRepoMeta).not.toHaveBeenCalled();

    vi.mocked(readCodeGraphyRepoMeta).mockReturnValueOnce(
      meta({ lastIndexedAt: null, lastIndexedCommit: null }),
    );

    expect(hasWorkspacePipelineIndex('/workspace', dependencies)).toBe(false);
    expect(dependencies.getCurrentCommitShaSync).not.toHaveBeenCalled();
  });

  it('returns false when persisted signatures do not match the current signatures', () => {
    const dependencies = {
      getCurrentCommitShaSync: vi.fn(() => 'abc123'),
      getPluginSignature: vi.fn(() => 'different-plugin-signature'),
      getSettingsSignature: vi.fn(() => 'settings-signature'),
    };

    expect(hasWorkspacePipelineIndex('/workspace', dependencies)).toBe(false);
    expect(dependencies.getCurrentCommitShaSync).not.toHaveBeenCalled();
  });

  it('treats a missing current commit as matching only when the persisted commit is also null', () => {
    const dependencies = {
      getCurrentCommitShaSync: vi.fn(() => null),
      getPluginSignature: vi.fn(() => 'plugin-signature'),
      getSettingsSignature: vi.fn(() => 'settings-signature'),
    };

    vi.mocked(readCodeGraphyRepoMeta).mockReturnValueOnce(
      meta({ lastIndexedCommit: null }),
    );
    expect(hasWorkspacePipelineIndex('/workspace', dependencies)).toBe(true);

    vi.mocked(readCodeGraphyRepoMeta).mockReturnValueOnce(meta());
    expect(hasWorkspacePipelineIndex('/workspace', dependencies)).toBe(false);
  });

  it('matches the stored commit when signatures are current', () => {
    const dependencies = {
      getCurrentCommitShaSync: vi.fn(() => 'abc123'),
      getPluginSignature: vi.fn(() => 'plugin-signature'),
      getSettingsSignature: vi.fn(() => 'settings-signature'),
    };

    expect(hasWorkspacePipelineIndex('/workspace', dependencies)).toBe(true);

    dependencies.getCurrentCommitShaSync.mockReturnValueOnce('def456');
    expect(hasWorkspacePipelineIndex('/workspace', dependencies)).toBe(false);
  });

  it('writes updated index metadata when a workspace root is available', async () => {
    vi.useFakeTimers();
    vi.setSystemTime(new Date('2026-04-16T08:45:00.000Z'));

    const warn = vi.fn();
    const dependencies = {
      getCurrentCommitSha: vi.fn(async () => 'def456'),
      getPluginSignature: vi.fn(() => 'next-plugin-signature'),
      getSettingsSignature: vi.fn(() => 'next-settings-signature'),
      warn,
    };

    await persistWorkspacePipelineIndexMetadata('/workspace', dependencies);

    expect(writeCodeGraphyRepoMeta).toHaveBeenCalledWith('/workspace', {
      version: 1,
      lastIndexedAt: '2026-04-16T08:45:00.000Z',
      lastIndexedCommit: 'def456',
      pluginSignature: 'next-plugin-signature',
      settingsSignature: 'next-settings-signature',
      pendingChangedFiles: [],
    });
    expect(warn).not.toHaveBeenCalled();
  });

  it('skips writes without a workspace root and warns on persistence failures', async () => {
    const warn = vi.fn();
    const dependencies = {
      getCurrentCommitSha: vi.fn(async () => 'def456'),
      getPluginSignature: vi.fn(() => 'next-plugin-signature'),
      getSettingsSignature: vi.fn(() => 'next-settings-signature'),
      warn,
    };

    await persistWorkspacePipelineIndexMetadata(undefined, dependencies);
    expect(writeCodeGraphyRepoMeta).not.toHaveBeenCalled();

    const error = new Error('disk full');
    vi.mocked(readCodeGraphyRepoMeta).mockImplementationOnce(() => {
      throw error;
    });

    await persistWorkspacePipelineIndexMetadata('/workspace', dependencies);

    expect(warn).toHaveBeenCalledWith(
      '[CodeGraphy] Failed to update repo index metadata.',
      error,
    );
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import { handlePythonImportStatement } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/pythonImports';
import {
  getIdentifierText,
  getLastPathSegment,
  getNodeText,
} from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/nodes';
import { resolvePythonModulePath } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/paths';
import { addImportRelation } from '../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/results';

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/nodes', () => ({
  getIdentifierText: vi.fn(),
  getLastPathSegment: vi.fn((value: string, separator: string) => value.split(separator).at(-1) ?? null),
  getNodeText: vi.fn((node?: { text?: string } | null) => node?.text ?? null),
}));

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/paths', () => ({
  resolvePythonModulePath: vi.fn(),
}));

vi.mock('../../../../src/extension/pipeline/plugins/treesitter/runtime/analyze/results', () => ({
  addImportRelation: vi.fn(),
}));

function createNode(overrides: Partial<{
  type: string;
  text: string;
  namedChildren: Array<unknown>;
  childForFieldName: (name: string) => unknown;
}> = {}) {
  return {
    type: 'import_statement',
    text: '',
    namedChildren: [],
    childForFieldName: () => null,
    ...overrides,
  };
}

describe('pipeline/plugins/treesitter/runtime/analyze/pythonImports', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('adds import relations and bindings for dotted-name and aliased imports', () => {
    vi.mocked(getIdentifierText).mockReturnValueOnce('tools').mockReturnValueOnce(null);
    vi.mocked(resolvePythonModulePath)
      .mockReturnValueOnce('/workspace/pkg/codegraphy/tools.py')
      .mockReturnValueOnce('/workspace/pkg/codegraphy/runtime.py');

    const importedBindings = new Map();
    const relations: never[] = [];
    const aliasedImport = createNode({
      type: 'aliased_import',
      namedChildren: [{ type: 'dotted_name', text: 'codegraphy.tools' }],
      childForFieldName: (name) =>
        name === 'name'
          ? { type: 'dotted_name', text: 'codegraphy.tools' }
          : name === 'alias'
            ? { type: 'identifier', text: 'tools' }
            : null,
    });
    const dottedImport = createNode({
      type: 'dotted_name',
      text: 'codegraphy.runtime',
    });

    expect(
      handlePythonImportStatement(
        createNode({ namedChildren: [aliasedImport, dottedImport] }) as never,
        '/workspace/pkg/app.py',
        '/workspace',
        relations,
        importedBindings as never,
      ),
    ).toEqual({ skipChildren: true });

    expect(addImportRelation).toHaveBeenNthCalledWith(
      1,
      relations,
      '/workspace/pkg/app.py',
      'codegraphy.tools',
      '/workspace/pkg/codegraphy/tools.py',
    );
    expect(addImportRelation).toHaveBeenNthCalledWith(
      2,
      relations,
      '/workspace/pkg/app.py',
      'codegraphy.runtime',
      '/workspace/pkg/codegraphy/runtime.py',
    );
    expect(importedBindings.get('tools')).toEqual({
      importedName: 'codegraphy.tools',
      resolvedPath: '/workspace/pkg/codegraphy/tools.py',
      specifier: 'codegraphy.tools',
    });
    expect(importedBindings.get('runtime')).toEqual({
      importedName: 'codegraphy.runtime',
      resolvedPath: '/workspace/pkg/codegraphy/runtime.py',
      specifier: 'codegraphy.runtime',
    });
    expect(getLastPathSegment).toHaveBeenCalledWith('codegraphy.runtime', '.');
  });

  it('ignores non-module children and falls back to the first named child for aliased imports', () => {
    vi.mocked(getIdentifierText).mockReturnValue('alias_tools');
    vi.mocked(resolvePythonModulePath).mockReturnValue('/workspace/pkg/codegraphy/tools.py');
    const importedBindings = new Map();
    const relations: never[] = [];
    const fallbackNameNode = { type: 'dotted_name', text: 'codegraphy.tools' };
    const childForFieldName = vi.fn((name: string) => {
      expect(['name', 'alias']).toContain(name);
      return name === 'alias' ? { type: 'identifier', text: 'alias_tools' } : null;
    });
    const aliasedImport = createNode({
      type: 'aliased_import',
      namedChildren: [fallbackNameNode],
      childForFieldName,
    });

    handlePythonImportStatement(
      createNode({
        namedChildren: [createNode({ type: 'identifier', text: 'ignored' }), aliasedImport],
      }) as never,
      '/workspace/pkg/app.py',
      '/workspace',
      relations,
      importedBindings as never,
    );

    expect(resolvePythonModulePath).toHaveBeenCalledTimes(1);
    expect(resolvePythonModulePath).toHaveBeenCalledWith(
      '/workspace/pkg/app.py',
      '/workspace',
      'codegraphy.tools',
    );
    expect(addImportRelation).toHaveBeenCalledTimes(1);
    expect(importedBindings.get('alias_tools')).toEqual({
      importedName: 'codegraphy.tools',
      resolvedPath: '/workspace/pkg/codegraphy/tools.py',
      specifier: 'codegraphy.tools',
    });
    expect(getNodeText).toHaveBeenCalledWith(fallbackNameNode);
    expect(getIdentifierText).toHaveBeenCalledWith({ type: 'identifier', text: 'alias_tools' });
  });

  it('skips import entries without a resolved specifier', () => {
    vi.mocked(getNodeText).mockReturnValue(null);
    const importedBindings = new Map();
    const relations: never[] = [];

    handlePythonImportStatement(
      createNode({
        namedChildren: [createNode({ type: 'dotted_name', text: 'ignored' })],
      }) as never,
      '/workspace/pkg/app.py',
      '/workspace',
      relations,
      importedBindings as never,
    );

    expect(resolvePythonModulePath).not.toHaveBeenCalled();
    expect(addImportRelation).not.toHaveBeenCalled();
    expect(importedBindings.size).toBe(0);
  });
});

import { describe, expect, it, vi } from 'vitest';
import type { IDiscoveredFile } from '../../../../src/core/discovery/contracts';
import type {
  IProjectedConnection,
  IFileAnalysisResult,
} from '../../../../src/core/plugins/types/contracts';
import { DEFAULT_EXCLUDE_PATTERNS } from '../../../../src/extension/config/defaults';
import { formatWorkspacePipelineLimitReachedMessage } from '../../../../src/extension/pipeline/discovery';
import type { IGraphData } from '../../../../src/shared/graph/types';
import { analyzeWorkspaceWithAnalyzer } from '../../../../src/extension/pipeline/analysis/analyze';

function createSource() {
  const emit = vi.fn();
  return {
    _analyzeFiles: vi.fn<
      (files: IDiscoveredFile[], workspaceRoot: string) => Promise<{
        fileAnalysis: Map<string, IFileAnalysisResult>;
        fileConnections: Map<string, IProjectedConnection[]>;
      }>
    >(async () => ({
      fileAnalysis: new Map(),
      fileConnections: new Map(),
    })),
    _buildGraphDataFromAnalysis: vi.fn<() => IGraphData>(() => ({
      nodes: [{ id: 'src/index.ts', label: 'index.ts', color: '#93C5FD' }],
      edges: [{ id: 'src/index.ts->src/utils.ts#import', from: 'src/index.ts', to: 'src/utils.ts' , kind: 'import', sources: [] }],
    } satisfies IGraphData)),
    _buildGraphData: vi.fn<() => IGraphData>(() => ({
      nodes: [{ id: 'src/index.ts', label: 'index.ts', color: '#93C5FD' }],
      edges: [{ id: 'src/index.ts->src/utils.ts#import', from: 'src/index.ts', to: 'src/utils.ts' , kind: 'import', sources: [] }],
    } satisfies IGraphData)),
    _eventBus: { emit },
    _lastDiscoveredFiles: [] as IDiscoveredFile[],
    _lastFileAnalysis: new Map(),
    _lastFileConnections: new Map<string, IProjectedConnection[]>(),
    _lastWorkspaceRoot: '',
    _preAnalyzePlugins: vi.fn(async () => undefined),
    getPluginFilterPatterns: vi.fn(() => ['**/*.generated.ts']),
  };
}

function createDependencies() {
  return {
    discover: vi.fn(async () => ({
      durationMs: 3,
      files: [] as IDiscoveredFile[],
      limitReached: false,
      totalFound: 0,
    })),
    getConfig: vi.fn(() => ({
      include: ['**/*'],
      maxFiles: 25,
      respectGitignore: true,
      showOrphans: true,
    })),
    getWorkspaceRoot: vi.fn<() => string | undefined>(() => '/workspace'),
    logInfo: vi.fn(),
    saveCache: vi.fn(),
    showWarningMessage: vi.fn(),
  };
}

describe('pipeline/analysis/analyze', () => {
  it('returns an empty graph when no workspace root is available', async () => {
    const source = createSource();
    const dependencies = createDependencies();
    dependencies.getWorkspaceRoot.mockReturnValue(undefined);

    await expect(
      analyzeWorkspaceWithAnalyzer(source as never, dependencies as never),
    ).resolves.toEqual({ nodes: [], edges: [] });

    expect(dependencies.logInfo).toHaveBeenCalledWith('[CodeGraphy] No workspace folder open');
    expect(dependencies.discover).not.toHaveBeenCalled();
    expect(source._preAnalyzePlugins).not.toHaveBeenCalled();
    expect(source._analyzeFiles).not.toHaveBeenCalled();
    expect(dependencies.saveCache).not.toHaveBeenCalled();
  });

  it('uses only default and plugin filters when user filters are omitted', async () => {
    const source = createSource();
    const dependencies = createDependencies();

    await analyzeWorkspaceWithAnalyzer(source as never, dependencies as never);

    expect(dependencies.discover).toHaveBeenCalledWith({
      rootPath: '/workspace',
      maxFiles: 25,
      include: ['**/*'],
      exclude: [...DEFAULT_EXCLUDE_PATTERNS, '**/*.generated.ts'],
      respectGitignore: true,
      signal: undefined,
    });
  });

  it('discovers, analyzes, caches, and emits lifecycle events', async () => {
    const source = createSource();
    const dependencies = createDependencies();
    const files = [
      { absolutePath: '/workspace/src/index.ts', relativePath: 'src/index.ts' },
    ] as IDiscoveredFile[];
    const fileAnalysis = new Map<string, IFileAnalysisResult>([
      ['src/index.ts', { filePath: '/workspace/src/index.ts', relations: [] }],
    ]);
    const fileConnections = new Map<string, IProjectedConnection[]>([['src/index.ts', []]]);
    const graphData: IGraphData = {
      nodes: [{ id: 'src/index.ts', label: 'index.ts', color: '#93C5FD' }],
      edges: [{ id: 'src/index.ts->src/utils.ts#import', from: 'src/index.ts', to: 'src/utils.ts' , kind: 'import', sources: [] }],
    };

    dependencies.discover.mockResolvedValue({
      durationMs: 4,
      files,
      limitReached: false,
      totalFound: 1,
    });
    source._analyzeFiles.mockResolvedValue({
      fileAnalysis,
      fileConnections,
    });
    source._buildGraphDataFromAnalysis.mockReturnValue(graphData);

    await expect(
      analyzeWorkspaceWithAnalyzer(
        source as never,
        dependencies as never,
        ['**/*.user.ts'],
        new Set<string>(['plugin.python']),
      ),
    ).resolves.toEqual(graphData);

    expect(dependencies.discover).toHaveBeenCalledOnce();
    expect(source._preAnalyzePlugins).toHaveBeenCalledWith(files, '/workspace', undefined);
    expect(source._analyzeFiles).toHaveBeenCalledWith(
      files,
      '/workspace',
      expect.any(Function),
      undefined,
    );
    expect(source._buildGraphDataFromAnalysis).toHaveBeenCalledWith(
      fileAnalysis,
      '/workspace',
      true,
      new Set<string>(['plugin.python']),
    );
    expect(source._lastDiscoveredFiles).toEqual(files);
    expect(source._lastFileAnalysis).toBe(fileAnalysis);
    expect(source._lastFileConnections).toBe(fileConnections);
    expect(source._lastWorkspaceRoot).toBe('/workspace');
    expect(dependencies.saveCache).toHaveBeenCalledOnce();
