import { beforeEach, describe, expect, it, vi } from 'vitest';
import { Connection, Database } from '@ladybugdb/core';
import {
  readRowsSync,
  runStatementSync,
  withConnection,
} from '../../../../src/extension/pipeline/database/cacheConnection';

vi.mock('@ladybugdb/core', () => ({
  Connection: vi.fn(),
  Database: vi.fn(),
}));

describe('pipeline/database/cacheConnection', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('closes every query result returned by runStatementSync', () => {
    const closeFirst = vi.fn();
    const closeSecond = vi.fn();
    const connection = {
      querySync: vi.fn().mockReturnValue([{ close: closeFirst }, { close: closeSecond }]),
    };

    runStatementSync(connection as never, 'MATCH (n) RETURN n');

    expect(connection.querySync).toHaveBeenCalledWith('MATCH (n) RETURN n');
    expect(closeFirst).toHaveBeenCalledOnce();
    expect(closeSecond).toHaveBeenCalledOnce();
  });

  it('reads rows from the first query result and still closes every result', () => {
    const getAllSync = vi.fn().mockReturnValue([{ filePath: 'src/app.ts' }]);
    const closeFirst = vi.fn();
    const closeSecond = vi.fn();
    const connection = {
      querySync: vi.fn().mockReturnValue([
        { getAllSync, close: closeFirst },
        { close: closeSecond },
      ]),
    };

    expect(readRowsSync(connection as never, 'MATCH (n) RETURN n')).toEqual([{ filePath: 'src/app.ts' }]);
    expect(getAllSync).toHaveBeenCalledOnce();
    expect(closeFirst).toHaveBeenCalledOnce();
    expect(closeSecond).toHaveBeenCalledOnce();
  });

  it('returns an empty array when rows cannot be read and still closes the result', () => {
    const close = vi.fn();
    const connection = {
      querySync: vi.fn().mockReturnValue({ close }),
    };

    expect(readRowsSync(connection as never, 'MATCH (n) RETURN n')).toEqual([]);
    expect(close).toHaveBeenCalledOnce();
  });

  it('tolerates missing query results when closing statements and reading rows', () => {
    const connection = {
      querySync: vi
        .fn()
        .mockReturnValueOnce(undefined)
        .mockReturnValueOnce([undefined]),
    };

    expect(() => runStatementSync(connection as never, 'MATCH (n) RETURN n')).not.toThrow();
    expect(readRowsSync(connection as never, 'MATCH (n) RETURN n')).toEqual([]);
  });

  it('best-effort closes query results even when close throws', () => {
    const connection = {
      querySync: vi.fn().mockReturnValue({ close: vi.fn().mockImplementation(() => {
        throw new Error('close failed');
      }) }),
    };

    expect(() => runStatementSync(connection as never, 'MATCH (n) RETURN n')).not.toThrow();
  });

  it('initializes the database, ensures the schema, runs the callback, and closes resources', () => {
    const initSync = vi.fn();
    const querySync = vi.fn().mockReturnValue({ close: vi.fn() });
    const closeConnection = vi.fn();
    const closeDatabase = vi.fn();
    const databaseInstance = { closeSync: closeDatabase };
    const connectionInstance = {
      initSync,
      querySync,
      closeSync: closeConnection,
    };
    vi.mocked(Database).mockImplementation(() => databaseInstance as never);
    vi.mocked(Connection).mockImplementation(() => connectionInstance as never);

    const value = withConnection('/workspace/.codegraphy/graph.lbug', (connection) => {
      expect(connection).toBe(connectionInstance);
      return 'ok';
    });

    expect(value).toBe('ok');
    expect(Database).toHaveBeenCalledWith('/workspace/.codegraphy/graph.lbug');
    expect(Connection).toHaveBeenCalledWith(databaseInstance);
    expect(initSync).toHaveBeenCalledOnce();
    expect(querySync).toHaveBeenCalledTimes(3);
    expect(querySync).toHaveBeenNthCalledWith(
      1,
      'CREATE NODE TABLE IF NOT EXISTS FileAnalysis(filePath STRING PRIMARY KEY, mtime INT64, size INT64, analysis STRING)',
    );
    expect(querySync).toHaveBeenNthCalledWith(
      2,
      'CREATE NODE TABLE IF NOT EXISTS Symbol(symbolId STRING PRIMARY KEY, filePath STRING, name STRING, kind STRING, signature STRING, rangeJson STRING, metadataJson STRING)',
    );
    expect(querySync).toHaveBeenNthCalledWith(
      3,
      'CREATE NODE TABLE IF NOT EXISTS Relation(relationId STRING PRIMARY KEY, filePath STRING, kind STRING, pluginId STRING, sourceId STRING, fromFilePath STRING, toFilePath STRING, fromNodeId STRING, toNodeId STRING, fromSymbolId STRING, toSymbolId STRING, specifier STRING, relationType STRING, variant STRING, resolvedPath STRING, metadataJson STRING)',
    );
    expect(closeConnection).toHaveBeenCalledOnce();
    expect(closeDatabase).toHaveBeenCalledOnce();
  });

  it('closes the connection and database when the callback throws', () => {
    const closeConnection = vi.fn();
    const closeDatabase = vi.fn();
    vi.mocked(Database).mockImplementation(() => ({ closeSync: closeDatabase }) as never);
    vi.mocked(Connection).mockImplementation(() => ({
      initSync: vi.fn(),
      querySync: vi.fn().mockReturnValue({ close: vi.fn() }),
      closeSync: closeConnection,
    }) as never);

    expect(() =>
      withConnection('/workspace/.codegraphy/graph.lbug', () => {
        throw new Error('boom');
      }),
    ).toThrow('boom');

    expect(closeConnection).toHaveBeenCalledOnce();
    expect(closeDatabase).toHaveBeenCalledOnce();
  });
});

import { describe, expect, it, vi } from 'vitest';
import type { IDiscoveredFile } from '../../../src/core/discovery/contracts';
import type { IProjectedConnection, IFileAnalysisResult } from '../../../src/core/plugins/types/contracts';
import { createEmptyWorkspaceAnalysisCache } from '../../../src/extension/pipeline/cache';
import { analyzeWorkspaceFiles } from '../../../src/extension/pipeline/fileAnalysis';

function createFile(relativePath: string): IDiscoveredFile {
  const extensionIndex = relativePath.lastIndexOf('.');
  const slashIndex = relativePath.lastIndexOf('/');

  return {
    absolutePath: `/workspace/${relativePath}`,
    extension: extensionIndex >= 0 ? relativePath.slice(extensionIndex) : '',
    name: slashIndex >= 0 ? relativePath.slice(slashIndex + 1) : relativePath,
    relativePath,
  };
}

function createImportAnalysis(): IFileAnalysisResult {
  return {
    filePath: '/workspace/src/index.ts',
    relations: [
      {
        kind: 'import',
        sourceId: 'test-source',
        specifier: './utils',
        type: 'static',
        resolvedPath: '/workspace/src/utils.ts',
        fromFilePath: '/workspace/src/index.ts',
        toFilePath: '/workspace/src/utils.ts',
      },
    ],
  };
}

function createEmptyAnalysis(
  filePath = '/workspace/src/index.ts',
): IFileAnalysisResult {
  return {
    filePath,
    relations: [],
  };
}

describe('pipeline/fileAnalysis', () => {
  it('reuses cached connections and backfills missing size on cache hits', async () => {
    const cache = createEmptyWorkspaceAnalysisCache();
    const cachedConnections: IProjectedConnection[] = [
      { specifier: './utils', resolvedPath: '/workspace/src/utils.ts', type: 'static' , sourceId: 'test-source', kind: 'import' },
    ];
    const cachedAnalysis = createImportAnalysis();
    cache.files['src/index.ts'] = {
      mtime: 25,
      analysis: cachedAnalysis,
    };

    const readContent = vi.fn(async () => 'ignored');
    const analyzeFile = vi.fn(async () => ({
      filePath: '/workspace/src/index.ts',
      relations: [],
    }));

    const result = await analyzeWorkspaceFiles({
      analyzeFile,
      cache,
      files: [createFile('src/index.ts')],
      getFileStat: vi.fn(async () => ({ mtime: 25, size: 99 })),
      readContent,
      workspaceRoot: '/workspace',
    });

    expect(result.cacheHits).toBe(1);
    expect(result.cacheMisses).toBe(0);
    expect(result.fileConnections.get('src/index.ts')).toEqual(cachedConnections);
    expect(result.fileAnalysis.get('src/index.ts')).toEqual(cachedAnalysis);
    expect(cache.files['src/index.ts'].size).toBe(99);
    expect(readContent).not.toHaveBeenCalled();
    expect(analyzeFile).not.toHaveBeenCalled();
  });

  it('keeps the cached size when a cache hit already has size data', async () => {
    const cache = createEmptyWorkspaceAnalysisCache();
    cache.files['src/index.ts'] = {
      mtime: 25,
      analysis: createEmptyAnalysis(),
      size: 12,
    };

    await analyzeWorkspaceFiles({
      analyzeFile: vi.fn(async () => createEmptyAnalysis()),
      cache,
      files: [createFile('src/index.ts')],
      getFileStat: vi.fn(async () => ({ mtime: 25, size: 99 })),
      readContent: vi.fn(async () => 'ignored'),
      workspaceRoot: '/workspace',
    });

    expect(cache.files['src/index.ts'].size).toBe(12);
  });

  it('analyzes uncached files and stores the new cache entry', async () => {
    const cache = createEmptyWorkspaceAnalysisCache();
    const connections: IProjectedConnection[] = [
      { specifier: './utils', resolvedPath: '/workspace/src/utils.ts', type: 'static' , sourceId: 'test-source', kind: 'import' },
    ];
    const analysis = createImportAnalysis();

    const result = await analyzeWorkspaceFiles({
      analyzeFile: vi.fn(async () => analysis),
      cache,
      files: [createFile('src/index.ts')],
      getFileStat: vi.fn(async () => ({ mtime: 50, size: 12 })),
      readContent: vi.fn(async () => "import './utils'"),
      workspaceRoot: '/workspace',
    });

    expect(result.cacheHits).toBe(0);
    expect(result.cacheMisses).toBe(1);
    expect(result.fileConnections.get('src/index.ts')).toEqual(connections);
    expect(result.fileAnalysis.get('src/index.ts')).toEqual(analysis);
    expect(cache.files['src/index.ts']).toEqual({
      mtime: 50,
      analysis,
      size: 12,
    });
  });

  it('treats stale cached entries as cache misses', async () => {
    const cache = createEmptyWorkspaceAnalysisCache();
    cache.files['src/index.ts'] = {
      mtime: 25,
      analysis: createEmptyAnalysis(),
      size: 12,
    };
    const readContent = vi.fn(async () => "import './utils'");
    const analyzeFile = vi.fn(async () => ({
      filePath: '/workspace/src/index.ts',
      relations: [],
    }));

    const result = await analyzeWorkspaceFiles({
      analyzeFile,
      cache,
      files: [createFile('src/index.ts')],
      getFileStat: vi.fn(async () => ({ mtime: 30, size: 99 })),
      readContent,
      workspaceRoot: '/workspace',
    });

    expect(result.cacheHits).toBe(0);
    expect(result.cacheMisses).toBe(1);
    expect(readContent).toHaveBeenCalledTimes(1);
    expect(analyzeFile).toHaveBeenCalledTimes(1);
  });

  it('emits file processed payloads for analyzed files', async () => {
    const emitFileProcessed = vi.fn();
    const analysis = createImportAnalysis();

    await analyzeWorkspaceFiles({
      analyzeFile: vi.fn(async () => analysis),
      cache: createEmptyWorkspaceAnalysisCache(),
      emitFileProcessed,
      files: [createFile('src/index.ts')],
      getFileStat: vi.fn(async () => ({ mtime: 10, size: 1 })),
      readContent: vi.fn(async () => "import './utils'"),
      workspaceRoot: '/workspace',
    });

    expect(emitFileProcessed).toHaveBeenCalledWith({
      filePath: 'src/index.ts',
      connections: [
        {
          specifier: './utils',
          resolvedPath: '/workspace/src/utils.ts',
        },
      ],
    });
  });

  it('stores zero mtime when file stats are unavailable', async () => {
    const cache = createEmptyWorkspaceAnalysisCache();

    await analyzeWorkspaceFiles({
      analyzeFile: vi.fn(async () => createEmptyAnalysis()),
      cache,
      files: [createFile('src/index.ts')],
      getFileStat: vi.fn(async () => null),
      readContent: vi.fn(async () => ''),
      workspaceRoot: '/workspace',
    });

    expect(cache.files['src/index.ts']).toEqual({
      mtime: 0,
      analysis: createEmptyAnalysis(),
      size: undefined,
    });
  });

  it('treats cached entries as misses when file stats are unavailable', async () => {
    const cache = createEmptyWorkspaceAnalysisCache();
    cache.files['src/index.ts'] = {
      mtime: 25,
      analysis: createEmptyAnalysis(),
    };
    const readContent = vi.fn(async () => '');
    const analyzeFile = vi.fn(async () => createEmptyAnalysis());

    await analyzeWorkspaceFiles({
      analyzeFile,
      cache,
      files: [createFile('src/index.ts')],
      getFileStat: vi.fn(async () => null),
      readContent,
      workspaceRoot: '/workspace',
    });

    expect(readContent).toHaveBeenCalledTimes(1);
    expect(analyzeFile).toHaveBeenCalledTimes(1);
  });

  it('reuses malformed cached entries without reading size from missing stats', async () => {
    const cache = createEmptyWorkspaceAnalysisCache();
    const cachedConnections: IProjectedConnection[] = [
      { specifier: './utils', resolvedPath: '/workspace/src/utils.ts', type: 'static' , sourceId: 'test-source', kind: 'import' },
    ];
    cache.files['src/index.ts'] = {
      mtime: undefined as unknown as number,
      analysis: createImportAnalysis(),
      size: undefined,
    };
    const readContent = vi.fn(async () => 'ignored');
    const analyzeFile = vi.fn(async () => createEmptyAnalysis());

    const result = await analyzeWorkspaceFiles({
      analyzeFile,
      cache,
      files: [createFile('src/index.ts')],
